const CLOUDINARY_CLOUD = "dcnk0cahf";
const CL_BASE = `https://res.cloudinary.com/${CLOUDINARY_CLOUD}/image/`;
const THUMB_T = "f_auto,q_auto,w_700,h_480,c_fill";
const FULL_T  = "f_auto,q_auto,w_1400,c_limit";

function photoUrl(p, size) {
  const t = size === "full" ? FULL_T : THUMB_T;
  if (p.startsWith(CL_BASE + "upload/")) {
    // Cloudinary upload URL — insert transforms after /upload/
    return p.replace("/upload/", `/upload/${t}/`);
  }
  if (p.startsWith("https://static.wixstatic.com/")) {
    // Wix CDN — proxy through Cloudinary fetch
    return `${CL_BASE}fetch/${t}/${encodeURIComponent(p)}`;
  }
  return null;
}

